const student = {
  name: 'Nour',
  scores: [85, 92, 78, 95, 88],

  calcAverage: function() {
    let sum = 0;
    for (let i = 0; i < this.scores.length; i++) {
      sum = sum + this.scores[i];
    }
    this.average = sum / this.scores.length;
    return this.average;
  },

  getHighest: function() {
    let max = this.scores[0];
    for (let i = 1; i < this.scores.length; i++) {
      if (this.scores[i] > max) {
        max = this.scores[i];
      }
    }
    this.highest = max;
    return this.highest;
  },

  getLowest: function() {
    let min = this.scores[0];
    for (let i = 1; i < this.scores.length; i++) {
      if (this.scores[i] < min) {
        min = this.scores[i];
      }
    }
    this.lowest = min;
    return this.lowest;
  },

  getGrade: function() {
    this.calcAverage();
    if (this.average >= 90) {
      this.grade = 'A';
    } else if (this.average >= 80) {
      this.grade = 'B';
    } else if (this.average >= 70) {
      this.grade = 'C';
    } else {
      this.grade = 'F';
    }
    return this.grade;
  },

  getReport: function() {
    this.getGrade();
    this.getHighest();
    this.getLowest();
    return `${this.name}: Average ${this.average}, Grade ${this.grade}, Highest ${this.highest}, Lowest ${this.lowest}`;
  }
};

console.log(student.getReport());

