  calcArea: function() {
    return this.width * this.height;
  }
};
console.log(rectangle.calcArea());

const weather = {
  temp: 35,
  city: 'Cairo',
  getReport: function() {
    return `${this.city}: ${this.temp >= 30 ? 'Hot!' : 'Nice weather'}`;
  }
};
console.log(weather.getReport());

const employee = {
  basicSalary: 5000,
  bonusPercentage: 20,
  calcBonus: function() {
    this.bonus = this.basicSalary * this.bonusPercentage / 100;
    return this.bonus;
  },
  calcTotalSalary: function() {
    this.calcBonus();
    this.totalSalary = this.basicSalary + this.bonus;
    return this.totalSalary;
  }
};
console.log(employee.calcTotalSalary());
